                .await?
        };

    let config = OAuthConfig {
        client_id,
        auth_url,
        token_url,
        redirect_uri: redirect_uri.to_string(),
        resource: Some(resource),
        scopes,
        extra_auth_params: Vec::new(),
        device_flow: false,
    };

