        assert!(!McpOAuthProvider::is_token_expired(&valid));

        // No expiry info
        let no_expiry = OAuthTokens {
            access_token: Secret::new("test".to_string()),
            refresh_token: None,
            id_token: None,
            account_id: None,
            expires_at: None,
