1938→    async fn oauth_start(&self, params: Value) -> ServiceResult {
1939→        let provider_name = params
1940→            .get("provider")
1941→            .and_then(|v| v.as_str())
1942→            .ok_or_else(|| "missing 'provider' parameter".to_string())?
1943→            .to_string();
1944→
1945→        let redirect_uri = params
1946→            .get("redirectUri")
1947→            .and_then(|v| v.as_str())
1948→            .map(str::trim)
1949→            .filter(|v| !v.is_empty())
1950→            .map(ToOwned::to_owned);
1951→
1952→        let mut oauth_config = load_oauth_config(&provider_name)
1953→            .ok_or_else(|| format!("no OAuth config for provider: {provider_name}"))?;
1954→
1955→        // User explicitly initiated OAuth for this provider; ensure it is enabled.
1956→        set_provider_enabled_in_config(&provider_name, true)?;
1957→        self.set_provider_enabled_in_memory(&provider_name, true);
1958→
1959→        // If tokens already exist (for example imported from the main/home config),
1960→        // skip launching a fresh OAuth flow and rebuild the registry immediately.
1961→        if self.has_oauth_tokens(&provider_name) {
1962→            let effective = self.effective_config();
1963→            let new_registry = self.build_registry(&effective);
1964→            let provider_summary = new_registry.provider_summary();
1965→            let model_count = new_registry.list_models().len();
1966→            let mut reg = self.registry.write().await;
1967→            *reg = new_registry;
1968→            info!(
1969→                provider = %provider_name,
1970→                provider_summary = %provider_summary,
1971→                models = model_count,
1972→                "oauth start skipped because provider already has tokens; rebuilt provider registry"
1973→            );
1974→            return Ok(serde_json::json!({
1975→                "alreadyAuthenticated": true,
1976→            }));
1977→        }
1978→
1979→        if oauth_config.device_flow {
1980→            return self
1981→                .oauth_start_device_flow(provider_name, oauth_config)
1982→                .await;
1983→        }
1984→
1985→        // Providers with a pre-registered redirect_uri (e.g. openai-codex
1986→        // registered as http://localhost:1455/auth/callback with OpenAI)
1987→        // must always use that URI in the authorization request.
1988→        // Overriding it with the gateway URL causes OAuth providers to
1989→        // reject the request with "unknown_error".
1990→        // For these providers we always use the local callback server.
1991→        let has_registered_redirect = !oauth_config.redirect_uri.is_empty();
1992→        let use_server_callback = redirect_uri.is_some() && !has_registered_redirect;
1993→        if !has_registered_redirect && let Some(uri) = redirect_uri {
1994→            oauth_config.redirect_uri = uri;
1995→        }
1996→
1997→        let port = callback_port(&oauth_config);
1998→        let oauth_config_for_pending = oauth_config.clone();
1999→        let flow = OAuthFlow::new(oauth_config);
2000→        let auth_req = flow.start().map_err(ServiceError::message)?;
2001→
2002→        let auth_url = auth_req.url.clone();
2003→        let verifier = auth_req.pkce.verifier.clone();
2004→        let expected_state = auth_req.state.clone();
2005→
2006→        let pending = PendingOAuthFlow {
2007→            provider_name: provider_name.clone(),
2008→            oauth_config: oauth_config_for_pending,
2009→            verifier: verifier.clone(),
2010→        };
2011→        self.pending_oauth
2012→            .write()
2013→            .await
2014→            .insert(expected_state.clone(), pending);
2015→
2016→        // Browser/server callback mode: callback lands on this gateway instance,
2017→        // then `/auth/callback` completes the exchange with `oauth_complete`.
2018→        if use_server_callback {
2019→            return Ok(serde_json::json!({
2020→                "authUrl": auth_url,
2021→            }));
2022→        }
2023→
2024→        // Spawn background task to wait for the callback and exchange the code
2025→        let token_store = self.token_store.clone();
