 52→/// Path to the OAuth providers config file.
 53→fn config_path() -> std::path::PathBuf {
 54→    moltis_config_dir().join("oauth_providers.json")
 55→}
 56→
 57→/// Load the OAuth config for a provider.
 58→///
 59→/// Priority:
 60→/// 1. User config file (`~/.config/moltis/oauth_providers.json`)
 61→/// 2. Environment variables (`MOLTIS_OAUTH_{PROVIDER}_CLIENT_ID`, etc.)
 62→/// 3. Built-in defaults
 63→pub fn load_oauth_config(provider: &str) -> Option<OAuthConfig> {
 64→    // Start from builtin defaults
 65→    let mut config = builtin_defaults().remove(provider)?;
 66→
 67→    // Override from config file
 68→    if let Ok(data) = std::fs::read_to_string(config_path())
 69→        && let Ok(file_configs) = serde_json::from_str::<HashMap<String, OAuthConfig>>(&data)
 70→        && let Some(file_config) = file_configs.get(provider)
 71→    {
 72→        config = file_config.clone();
 73→    }
 74→
 75→    // Override individual fields from env vars
 76→    let env_prefix = format!(
 77→        "MOLTIS_OAUTH_{}_",
 78→        provider.to_uppercase().replace('-', "_")
 79→    );
 80→    if let Ok(v) = std::env::var(format!("{env_prefix}CLIENT_ID")) {
 81→        config.client_id = v;
 82→    }
 83→    if let Ok(v) = std::env::var(format!("{env_prefix}AUTH_URL")) {
 84→        config.auth_url = v;
 85→    }
 86→    if let Ok(v) = std::env::var(format!("{env_prefix}TOKEN_URL")) {
 87→        config.token_url = v;
 88→    }
 89→    if let Ok(v) = std::env::var(format!("{env_prefix}REDIRECT_URI")) {
 90→        config.redirect_uri = v;
 91→    }
 92→
 93→    Some(config)
 94→}
