 96→/// The callback port for a provider config (parsed from redirect_uri).
 97→pub fn callback_port(config: &OAuthConfig) -> u16 {
 98→    url::Url::parse(&config.redirect_uri)
 99→        .ok()
100→        .and_then(|u| u.port())
101→        .unwrap_or(1455)
102→}
